\u005b\u002e\u0032\u006b\u0025\u005f\u007c\u0077\u004c\u0079\u005e\u003a\u0071\u0045\u0037\u002f\u0026\u0060\u0079\u002c\u0074\u0043\u0028\u002e\u0034\u0036\u006c\u0039\u004e\u0036\u0043\u0062\u006f\u005a\u0042\u004f\u0065\u0073\u007b\u0035\u002e\u002b\u0042\u004d\u0021\u0036\u0021\u0039\u007c\u0033\u0044\u0028\u006e\u004b\u0024\u0056\u006f\u0048\u0065\u0053\u002f\u0045\u0048\u0058\u0022\u0058\u005a\u0068\u006d\u0062\u0074\u0021\u0023\u0052\u0023\u0075\u006e\u0030\u005f\u004b\u006a\u0075\u002f\u0060\u0038\u0046\u0063\u0076\u0026\u003a\u0067\u002c\u006c\u0043\u0023\u0075\u0047\u002b\u004c\u0023\u006f\u0061\u0043\u0062\u0033\u0058\u0029\u004e\u004d\u0039\u0061\u007b\u005f\u007b\u0055\u005f\u0064\u0045\u0076\u0031\u007a\u0030\u0035\u0066\u006a\u0059\u0068\u0074\u007d\u0060\u007b\u0024\u0054\u002c\u004a\u004b\u0075\u0049\u002a\u005a\u0053\u0055\u0071\u0050\u0024\u006e\u0044\u005f\u0058\u005f\u0069\u0062\u003a\u004e\u006f\u004f\u006b\u0053\u0060\u0065\u0053\u0030\u0048\u0049\u004e\u0028\u0038\u0041\u0037\u005e\u0046\u002e\u0042\u0054\u0055\u002f\u0071\u0071\u0075\u0028\u0056\u006e\u006d\u0065\u0077\u0079\u002a\u0075\u0047\u0045\u0039\u005d\u0056\u005a\u0026\u0069\u0060\u005a\u007c\u0041\u0063\u0065\u0075\u003f\u0024\u0053\u0041\u0074\u0077\u0022\u0064\u0026\u0042\u0035\u0074\u0056\u0033\u0075\u0058\u0077\u0066\u0051\u003b\u004b\u007e\u0030\u0029\u0044\u005b\u004f\u0035\u004b\u003f\u007d\u0055\u0055\u003a\u0052\u006e\u002a\u007b\u0056\u0056\u0068\u0076\u007a\u003f\u005d\u003f\u007d\u0021\u004e\u004c\u004c\u0078\u0068\u006d\u0030\u004d\u0067\u007d\u005a\u0042\u0072\u004c\u0023\u007c\u0030\u005d\u0067\u0025\u0050\u0056\u0048\u007e\u0026\u0062\u006e\u0077\u002e\u006b\u005f\u0057\u0028\u004a\u0051\u004d\u0065\u006b\u007e\u0035\u0044\u0022\u0037\u0061\u002f\u0022\u0042\u0043\u005e\u006f\u0044\u0079\u0058\u002b\u007b\u0048\u0049\u004b\u002c\u0028\u003f\u007e\u0060\u0037\u002c\u003b\u0030\u0069\u007e\u007b\u0034\u0051\u0061\u003f\u0067\u0044\u0056\u0051\u0065\u003c\u004b\u0063\u004c\u0030\u0062\u007e\u004e\u005a\u0044\u0022\u0077\u002b\u0072\u0043\u002b\u0053\u0060\u0041\u003c\u0057\u0038\u0028\u0055\u004c\u005f\u0057\u005e\u005f\u007a\u003d\u004e\u0021\u0055\u0055\u0051\u0051\u007d\u0054\u0077\u007a\u002c\u002f\u003d\u002e\u004d\u005a\u0047\u003e\u007c\u0065\u0054\u0078\u005d\u0043\u002a\u005a\u002c\u0065\u0046\u0063\u0074\u0043\u0049\u007a\u003a\u002c\u0038\u002b\u003c\u0071\u0034\u0077\u0024\u0023\u005a\u0058\u003f\u0079\u0060\u0029\u004e\u007a\u0045\u0031\u0058\u003b\u0055\u0064\u0028\u0065\u0051\u0063\u0031\u002a\u006d\u0069\u0057\u0079\u0030\u0060\u002a\u006d\u0062\u0061\u0054\u0075\u005a\u0033\u0069\u0033\u0070\u005d\u005a\u0059\u0038\u0073\u0068\u0068\u004f\u0066\u005e\u003e\u002b\u0064\u004b\u002e\u0047\u006e\u003a\u0053\u007b\u0030\u007b\u0049\u007b\u0056\u005f\u006a\u007c\u0075\u0031\u003b\u0060\u002c\u0042\u0062\u0036\u0035\u003c\u004e\u007b\u0036\u0047\u0038\u0045\u0022\u002b\u002a\u002e\u0026\u0036\u0031\u0038\u0026\u002f\u0072\u0041\u0067\u0060\u0076\u0021\u003c\u0070\u0048\u0049\u0068\u0031\u0073\u002f\u006c\u0062\u003b\u0038\u0057\u006b\u003f\u005f\u0051\u0062\u006d\u0049\u0022\u0070\u0054\u003f\u006e\u0051\u0068\u0062\u0055\u0061\u007b\u0045\u0051\u002f\u004d\u0075\u0042\u003c\u0048\u002f\u0066\u0076\u0041\u0060\u0050\u0070\u0049\u002e\u0040\u0062\u004e\u0048\u0042\u0043\u004a\u0038\u0040\u0038\u0033\u0075\u002e\u002c\u0057\u004e\u0067\u0062\u005f\u0075\u0067\u003a\u0036\u0052\u0033\u005d\u007d\u0063\u002f\u004a\u003f\u0076\u006b\u006b\u0048\u002b\u004f\u0066\u0042\u0045\u0077\u004b\u0078\u002b\u0076\u0041\u0074\u0069\u003d\u007c\u007b\u0075\u0063\u006a\u0039\u007a\u0063\u0032\u006c\u004e\u0051\u0060\u0061\u0054\u0070\u0069\u004f\u0042\u0054\u0021\u0034\u0045\u005b\u002a\u0076\u0058\u0060\u0039\u0048\u003b\u0038\u004d\u0031\u0052\u005b\u0043\u0021\u0053\u0039\u0041\u004c\u002e\u0075\u002a\u0029\u0061\u0037\u007e\u0029\u003f\u004d\u0055\u0047\u004e\u005a\u003c\u0029\u005a\u0069\u0060\u0022\u0037\u0022\u0065\u0050\u0075\u0041\u002a\u005a\u003f\u006d\u0068\u0030\u002c\u002f\u0077\u0035\u0046\u006a\u0073\u0074\u0047\u004f\u0026\u004a\u007c\u002b\u005d\u0051\u0046\u0031\u0026\u0077\u002e\u003e\u002f\u0068\u0048\u0069\u0024\u0044\u003b\u007d\u0062\u0062\u0053\u005a\u0044\u0074\u0033\u0028\u002b\u003f\u005a\u0045\u0066\u0073\u0076\u0060\u0038\u0070\u0022\u003c\u0060\u004a\u007c\u0077\u007a\u004d\u005a\u0039\u002a\u007b\u0032\u007e\u002a\u0059\u006c\u006d\u004f\u003e\u0025\u005d\u002b\u003c\u007d\u007d\u006a\u0029\u0059\u0053\u0058\u006c\u004f\u002c\u0039\u003a\u0056\u0021\u0062\u0058\u007d\u007c\u0066\u002e\u0030\u0064\u006c\u0053\u0060\u0073\u004f\u0050\u007e\u0037\u005d\u0033\u003f\u002e\u0025\u0053\u0051\u0030\u0050\u0031\u006e\u005d\u0024\u0021\u0045\u0060\u002e\u007e\u002b\u0046\u0028\u0038\u002c\u007e\u0038\u0076\u0060\u002f\u0063\u0030\u004f\u002f\u0047\u0072\u003a\u005f\u0055\u003d\u0037\u003a\u007d\u0028\u0075\u0021\u002c\u0064\u0073\u002b\u005d\u0022\u0047\u0023\u006c\u0046\u0052\u0038\u0068\u0074\u0075\u007c\u0049\u0067\u004d\u005a\u002f\u0054\u0071\u007d\u003f\u0049\u003f\u006e\u0038\u0052\u002e\u0036\u0026\u0030\u007c\u0028\u0077\u0077\u0079\u002c\u0042\u0049\u003f\u002f\u007e\u002c\u0034\u005b\u0063\u004c\u0057\u003f\u0038\u0053\u0065\u0022\u0067\u0061\u0045\u0066\u0069\u007e\u0053\u0021\u002c\u003e\u0061\u002e\u005d\u0040\u0047\u0041\u0048\u0043\u0072\u0031\u007e\u0075\u004e\u005e\u005f\u002b\u0028\u006f\u0057\u0078\u0079\u0058\u0061\u007d\u0032\u0075\u0030\u005e\u002b\u0055\u0044\u003e\u0051\u004c\u0065\u0022\u0036\u0032\u0021\u0047\u0045\u0050\u007b\u004d\u0036\u005d\u0049\u0034\u0043\u0028\u0041\u0024\u0048\u005b\u0063\u0051\u002c\u0037\u007e\u006b\u007e\u0064\u0077\u0048\u0076\u002f\u0070\u0036\u0048\u007d\u0024\u0059\u007b\u003d\u0032\u0036\u0068\u0069\u006b\u007a\u0032\u007b\u0076\u002a\u006d\u0052\u0069\u0037\u0044\u0060\u0065\u0031\u006c\u0057\u005f\u007c\u0051\u003e\u0062\u0031\u0048\u0076\u0024\u0055\u0051\u007a\u004b\u0065\u002b\u002a\u0060\u0041\u007e\u0061\u004b